            aOrbiterB = (aOrbiterB ^ aOrbiterG) ^ 0x958B80B084D2CAACULL;
            aOrbiterB = RotL64((aOrbiterB * 0x7DF335E8723D25FDULL), 23U);
            //
            aOrbiterB = (aOrbiterB + aOrbiterI) + 0xBDEDAB5C9A77E5DBULL;
            aOrbiterD = ((aOrbiterD ^ aOrbiterB) ^ 0xF5D6958574D583DDULL) ^ aPhaseCOrbiterUpdateSaltB[(((31U - aIndex) + 17U)) & S_SALT1];
            aOrbiterD = RotL64((aOrbiterD * 0x97CACD022E707A79ULL), 47U);
            //
            aOrbiterC = (aOrbiterC + aOrbiterF) + 0x773BCCC70BB7DB0DULL;
            aOrbiterI = (aOrbiterI ^ aOrbiterC) ^ 0xBBB021621E6BCF8BULL;
            aOrbiterI = RotL64((aOrbiterI * 0x197707C2208A6C87ULL), 27U);
            //
            aOrbiterA = ((aOrbiterA + aOrbiterB) + 0xF77F167DE70998BEULL) + aPhaseCOrbiterUpdateSaltA[(((31U - aIndex) + 6U)) & S_SALT1];
            aOrbiterJ = (aOrbiterJ ^ aOrbiterA) ^ 0xBA6D9842CCB7F3B5ULL;
            aOrbiterJ = RotL64((aOrbiterJ * 0xB60CE697B11A0D1DULL), 53U);
            //
            aOrbiterF = ((aOrbiterF + aOrbiterG) + 0xB4B5E6E9DB2294CEULL) + aPhaseCOrbiterUpdateSaltC[(((31U - aIndex) + 26U)) & S_SALT1];
            aOrbiterA = (aOrbiterA ^ aOrbiterF) ^ 0xB9F0B4D2093EBA87ULL;
            aOrbiterA = RotL64((aOrbiterA * 0xBB6A91572D56DC85ULL), 57U);
            //
            aOrbiterJ = ((aOrbiterJ + aOrbiterD) + 0x56EBF94A24A43062ULL) + aPhaseCOrbiterUpdateSaltD[((aIndex + 25U)) & S_SALT1];
            aOrbiterG = (aOrbiterG ^ aOrbiterJ) ^ 0x7C6BE8B1DDEACFA3ULL;
            aOrbiterG = RotL64((aOrbiterG * 0xE69DDE0D868D60D3ULL), 5U);
