            aWandererB = aWandererB ^ ((RotL64(aCross, 47U) + RotL64(aOrbiterG, 51U)) + aOrbiterE);
            aWandererJ = aWandererJ + (((RotL64(aIngress, 23U) + RotL64(aOrbiterC, 19U)) + aOrbiterG) + RotL64(aCarry, 51U));
            aWandererG = aWandererG ^ ((RotL64(aPrevious, 5U) + aOrbiterB) + RotL64(aOrbiterC, 23U));
            aWandererD = aWandererD + (((RotL64(aScatter, 60U) + aOrbiterJ) + RotL64(aOrbiterB, 12U)) + RotL64(aCarry, 5U));
            aWandererA = aWandererA ^ ((RotL64(aPrevious, 29U) + RotL64(aOrbiterB, 47U)) + aOrbiterG);
            aWandererH = aWandererH + ((RotL64(aIngress, 13U) + RotL64(aOrbiterJ, 37U)) + aOrbiterD);
            aWandererF = aWandererF ^ (((RotL64(aCross, 53U) + aOrbiterJ) + RotL64(aOrbiterA, 43U)) + aPhaseCWandererUpdateSaltD[(((31U - aIndex) + 13U)) & S_SALT1]);
